B.aYd=new A.fn(B.aSe,2,t.fF)
B.Z9=new A.mw("Fachanwalt f\xfcr Arbeitsrecht","K\xfcndigung oder Aufhebungsvertrag pr\xfcfen und die Abfindung verhandeln.","Ein Fachanwalt f\xfcr Arbeitsrecht kann deine K\xfcndigung oder den Aufhebungsvertrag pr\xfcfen, die Erfolgsaussichten einer K\xfcndigungsschutzklage einsch\xe4tzen und die Abfindung verhandeln. Wichtig ist die Drei-Wochen-Frist des \xa7 4 KSchG: Nach Zugang einer schriftlichen K\xfcndigung bleibt nur diese Zeit, um Klage zu erheben.","Qualifizierte Kanzleien findest du \xfcber das amtliche Anwaltsverzeichnis der Bundesrechtsanwaltskammer oder die Rechtsanwaltskammer deines Bezirks. ExitKompass vermittelt keine Kanzleien und verdient nichts an diesem Hinweis.",B.acG,B.aYd)
B.cH={}
B.tV=new A.fn(B.cH,0,t.fF)
B.Za=new A.mw("Rechtsschutzversicherung pr\xfcfen","Bevor Beratungs- oder Prozesskosten entstehen.","Hast du eine Rechtsschutzversicherung mit Arbeitsrechtsschutz, \xfcbernimmt sie oft Anwalts- und Gerichtskosten. Pr\xfcfe die Wartezeit (meist drei Monate) und ob der Streitfall schon vor Vertragsbeginn angelegt war. Vor dem ersten Anwaltstermin lohnt sich eine Deckungsanfrage.","Steht in deiner Police oder erf\xe4hrst du direkt bei deiner Versicherung. ExitKompass empfiehlt keinen bestimmten Anbieter.",B.c9,B.tV)
B.aJ3=s(["BerHG","\xa7\xa7 114 ff. ZPO"],t.s)
B.Z7=new A.mw("Beratungs- und Prozesskostenhilfe","Wenn anwaltliche Hilfe finanziell schwerf\xe4llt.","Mit geringem Einkommen kannst du beim \xf6rtlichen Amtsgericht einen Beratungshilfeschein f\xfcr eine Erstberatung beantragen (Eigenanteil rund 15 \u20ac). F\xfcr ein Gerichtsverfahren gibt es Prozesskostenhilfe. Beides beantragst du beim Amtsgericht deines Wohnorts.","Rechtsantragstelle des Amtsgerichts am Wohnort.",B.aJ3,B.tV)
B.aNJ=s(["\xa7 38 SGB III","\xa7 141 SGB III"],t.s)
B.aSl={sperrzeit_eigenkuendigung:0,sperrzeit_wahrscheinlich:1,ruhen_158:2,alg_gedeckelt:3}
B.aY8=new A.fn(B.aSl,4,t.fF)
B.Z8=new A.mw("Agentur f\xfcr Arbeit: fr\xfch melden","Sobald du von der Beendigung erf\xe4hrst.","Melde dich sp\xe4testens drei Tage nach Kenntnis vom Ende arbeitsuchend \u2013 bei mehr als drei Monaten Vorlauf sp\xe4testens drei Monate vorher (\xa7 38 SGB III), sonst droht eine Minderung. Zum ersten Tag der Besch\xe4ftigungslosigkeit meldest du dich arbeitslos (\xa7 141 SGB III). Beides geht online oder pers\xf6nlich; die Agentur ber\xe4t auch zu ALG und Weiterbildung.","Agentur f\xfcr Arbeit \u2013 online oder in der \xf6rtlichen Dienststelle.",B.aNJ,B.aY8)
B.aMK=s(["\xa7 188 SGB V","\xa7 5 SGB V"],t.s)
B.aSn={kv_luecke:0}
B.aY5=new A.fn(B.aSn,1,t.fF)
B.Z6=new A.mw("Krankenversicherung kl\xe4ren","F\xfcr Monate ohne Gehalt und ohne ALG.","W\xe4hrend des ALG-Bezugs bist du in der Regel \xfcber die Agentur versichert. In L\xfcckenmonaten ohne Gehalt und ohne ALG musst du deinen Versicherungsschutz selbst sichern \u2013 etwa \xfcber die freiwillige Weiterversicherung oder die Familienversicherung. Melde dich fr\xfch bei deiner Krankenkasse; r\xfcckwirkende L\xfccken werden teuer. Privatversicherte haben eigene Regeln.","Deine gesetzliche Krankenkasse bzw. dein privater Versicherer.",B.aMK,B.aY5)
B.aK1=s(["\xa7 102 BetrVG"],t.s)
B.Z5=new A.mw("Betriebsrat und Gewerkschaft","Wenn es einen Betriebsrat oder eine Gewerkschaft gibt.","Der Betriebsrat muss vor jeder K\xfcndigung angeh\xf6rt werden (\xa7 102 BetrVG) \u2013 eine unterbliebene Anh\xf6rung macht die K\xfcndigung unwirksam. Bist du Gewerkschaftsmitglied, geh\xf6ren arbeitsrechtliche Beratung und Rechtsschutz meist zum Mitgliedsbeitrag.","Betriebsrat im Unternehmen; deine Gewerkschaft.",B.aK1,B.tV)
B.aLm=s([B.Z9,B.Za,B.Z7,B.Z8,B.Z6,B.Z5],t.jQ)
B.aLo=s(["Mon","Tue","Wed","Thu","Fri","Sat","Sun"],t.s)
B.eK=new A.lV(0,"leading")
B.d7=new A.lV(1,"title")
B.eL=new A.lV(2,"subtitle")
B.i8=new A.lV(3,"trailing")
B.aLt=s([B.eK,B.d7,B.eL,B.i8],A.a7("p<lV>"))
