B.aLI=s([B.f3,B.eq,B.iA,B.f4],A.a7("p<mj>"))
B.Rw=new A.cM("Grundsatz","Einen allgemeinen gesetzlichen Anspruch auf eine Abfindung gibt es in Deutschland nicht. Eine Abfindung ist meist das Ergebnis einer Einigung \u2013 etwa in einem Vergleich vor dem Arbeitsgericht oder in einem Aufhebungsvertrag.")
B.R7=new A.cM("Die wichtigsten Ausnahmen","Ein Anspruch kann sich ergeben aus einem Abfindungsangebot bei betriebsbedingter K\xfcndigung (\xa7 1a KSchG), aus einem Sozialplan (\xa7\xa7 112, 112a BetrVG), aus einem Nachteilsausgleich (\xa7 113 BetrVG) oder aus einem gerichtlichen Aufl\xf6sungsurteil (\xa7\xa7 9, 10 KSchG).")
B.R3=new A.cM("Warum trotzdem oft gezahlt wird","Auch ohne Anspruch bieten viele Arbeitgeber eine Abfindung an, um das Kosten- und Prozessrisiko einer K\xfcndigungsschutzklage zu vermeiden. Genau darin liegt der Verhandlungsspielraum.")
B.aJ1=s([B.Rw,B.R7,B.R3],t.aX)
B.aLG=s(["\xa7 1a KSchG","\xa7\xa7 9, 10 KSchG","\xa7\xa7 112, 112a, 113 BetrVG"],t.s)
B.RF=new A.hN(B.id,"Habe ich Anspruch auf eine Abfindung?","Meistens nein \u2013 aber es gibt wichtige Ausnahmen und viel Verhandlungsspielraum.",B.aJ1,B.aLG)
B.Rb=new A.cM("Die Faustformel","Als grobe Orientierung gilt: ein halbes Bruttomonatsgehalt je Jahr der Betriebszugeh\xf6rigkeit. Diese Gr\xf6\xdfe nennt auch \xa7 1a KSchG als Regelabfindung. Sie ist ein Anhaltspunkt, keine Obergrenze und kein Anspruch.")
B.R1=new A.cM("Was die H\xf6he beeinflusst","Wie gut die Erfolgsaussichten einer K\xfcndigungsschutzklage sind, wie dringend der Arbeitgeber die Trennung braucht, die Dauer der Betriebszugeh\xf6rigkeit und die Lage am Arbeitsmarkt wirken sich auf die tats\xe4chliche H\xf6he aus.")
B.R6=new A.cM("Mehr als nur Geld","Verhandelbar sind neben dem Betrag oft auch die Zeugnisnote, eine bezahlte Freistellung, der Verzicht auf R\xfcckzahlungsklauseln, der Auszahlungszeitpunkt (steuerlich relevant) und Leistungen wie Outplacement.")
B.aPr=s([B.Rb,B.R1,B.R6],t.aX)
B.aNa=s(["\xa7 1a KSchG"],t.s)
B.Rx=new A.hN(B.id,"Wie hoch f\xe4llt eine Abfindung \xfcblicherweise aus?","Die Faustformel als Orientierung \u2013 und warum sie nur ein Startpunkt ist.",B.aPr,B.aNa)
B.Ro=new A.cM("Prozessrisiko als Druckmittel","Eine fristgerechte K\xfcndigungsschutzklage h\xe4lt den Rechtsweg offen. F\xfcr den Arbeitgeber bedeutet ein laufendes Verfahren Unsicherheit, Zeit und Kosten \u2013 das erh\xf6ht die Bereitschaft, sich per Vergleich zu einigen.")
B.Rp=new A.cM("Auszahlung ins Folgejahr","Der Zeitpunkt der Auszahlung kann die Steuerlast ver\xe4ndern (Progression, F\xfcnftelregelung). Ob sich eine Verschiebung lohnt, l\xe4sst sich im Rechner dieser App durchspielen.")
B.Rf=new A.cM("Nicht unter Druck unterschreiben","F\xfcr einen Aufhebungsvertrag gibt es keine gesetzliche Bedenkzeit und kein Widerrufsrecht. Einmal unterschrieben, gilt er \u2013 deshalb ist Ruhe vor der Unterschrift wichtiger als Tempo.")
B.aFs=s([B.Ro,B.Rp,B.Rf],t.aX)
B.aNc=s(["\xa7 34 EStG","\xa7 4 KSchG"],t.s)
B.RE=new A.hN(B.id,"Verhandlungshebel bei Abfindung und Aufhebung","Prozessrisiko, Fristen und Timing sind deine st\xe4rksten Argumente.",B.aFs,B.aNc)
B.Rd=new A.cM("Vertrauen \u2192 Interdependenz","Vertrauen ist subjektiv und braucht Zeit; es garantiert keine Gegenleistung. Wirksamer ist es, die Anreize zu koppeln: Wenn beide Seiten erkennen, dass Zusammenarbeit im eigenen Interesse liegt, tr\xe4gt die Einigung von selbst.")
B.Rj=new A.cM("Zuh\xf6ren \u2192 proaktiv fragen","Blo\xdfes (auch aktives) Zuh\xf6ren ist reaktiv. Wer die Verhandlung f\xfchren will, stellt zuerst Fragen und lenkt so das Gespr\xe4ch dorthin, wo am meisten zu lernen ist.")
B.Rt=new A.cM("Transparent \u2192 durchscheinend auf der Sache","Bei Beziehung und Kommunikation darfst du offen sein. Auf der Sachebene gilt: nur so viel preisgeben, wie n\xf6tig ist, damit die Gegenseite eine Einigung anstrebt \u2013 nicht mehr.")
B.R0=new A.cM("Nett & fair \u2192 positiv und vern\xfcnftig",'Nettigkeit kann als Schw\xe4che gelesen werden. Sei stattdessen positiv, aber nicht naiv, und statt \u201esubjektiv fair" lieber \u201evern\xfcnftig": ein Vorschlag, der im Wertesystem beider Seiten nachvollziehbar ist.')
B.R4=new A.cM("Treu zur Person \u2192 treu zum Prozess","Bleib dem fairen Verhandlungsprozess verpflichtet, nicht bedingungslos der Gegenseite. Und verpflichte dich dem guten Prozess \u2013 nicht einem bestimmten Ergebnis, das du ohnehin nicht garantieren kannst.")
B.R8=new A.cM("Das eigentliche Werkzeug: bewusster Machtverzicht",'Auf Machtspiele zu verzichten ist keine Schw\xe4che, sondern eine strategische Entscheidung, die oft zu besseren Ergebnissen f\xfchrt. (Nach \u201eGetting to Yes" von Fisher/Ury.)')
B.aM8=s([B.Rd,B.Rj,B.Rt,B.R0,B.R4,B.R8],t.aX)
B.aP5=s(["Getting to Yes (Fisher/Ury)"],t.s)
B.RG=new A.hN(B.id,"Sieben Mythen der Win-win-Verhandlung","Nett, fair und vertrauensvoll allein macht dich in der Verhandlung nicht stark \u2013 hier die wirksameren Strategien.",B.aM8,B.aP5)
B.R9=new A.cM("Zwei Voraussetzungen","Das K\xfcndigungsschutzgesetz (KSchG) gilt, wenn das Arbeitsverh\xe4ltnis l\xe4nger als sechs Monate bestanden hat und im Betrieb in der Regel mehr als zehn Arbeitnehmer besch\xe4ftigt sind (Kleinbetriebsklausel).")
B.R5=new A.cM("Wenn es greift","Dann braucht eine ordentliche K\xfcndigung einen anerkannten Grund \u2013 betriebsbedingt, verhaltensbedingt oder personenbedingt \u2013 und muss sozial gerechtfertigt sein.")
B.Ri=new A.cM("Auch im Kleinbetrieb","Selbst ohne KSchG darf eine K\xfcndigung nicht sitten- oder treuwidrig sein, und es gelten Formvorschriften, Fristen und der Sonderk\xfcndigungsschutz.")
B.aN7=s([B.R9,B.R5,B.Ri],t.aX)
B.az8=s(["\xa7 1 KSchG","\xa7 23 KSchG"],t.s)
B.RB=new A.hN(B.kj,"Gilt der K\xfcndigungsschutz f\xfcr mich?","Das K\xfcndigungsschutzgesetz greift erst ab bestimmten Voraussetzungen.",B.aN7,B.az8)
B.Ru=new A.cM("Nur schriftlich","Eine K\xfcndigung muss schriftlich mit eigenh\xe4ndiger Unterschrift erfolgen (\xa7 623 BGB). Eine K\xfcndigung per E-Mail, SMS oder Messenger ist unwirksam.")
B.Rn=new A.cM("Betriebsrat anh\xf6ren","Gibt es einen Betriebsrat, muss er vor jeder K\xfcndigung angeh\xf6rt werden (\xa7 102 BetrVG). Ohne ordnungsgem\xe4\xdfe Anh\xf6rung ist die K\xfcndigung unwirksam.")
B.Rs=new A.cM("K\xfcndigungsfristen","Die gesetzlichen Fristen richten sich nach \xa7 622 BGB und verl\xe4ngern sich f\xfcr Arbeitgeberk\xfcndigungen mit der Dauer der Betriebszugeh\xf6rigkeit. Im Vertrag oder Tarifvertrag k\xf6nnen abweichende Fristen stehen.")
B.aLL=s([B.Ru,B.Rn,B.Rs],t.aX)
B.aNj=s(["\xa7 623 BGB","\xa7 622 BGB","\xa7 102 BetrVG"],t.s)
B.RA=new A.hN(B.kj,"Formfehler und Fristen: Wann eine K\xfcndigung unwirksam ist","Schriftform, Unterschrift, Betriebsratsanh\xf6rung \u2013 Formfehler z\xe4hlen.",B.aLL,B.aNj)
B.Ra=new A.cM("Drei Wochen ab Zugang","Wer sich gegen eine K\xfcndigung wehren will, muss innerhalb von drei Wochen ab Zugang der schriftlichen K\xfcndigung K\xfcndigungsschutzklage beim Arbeitsgericht erheben (\xa7 4 KSchG).")
B.Re=new A.cM("Was nach Fristablauf passiert","Wird die Frist vers\xe4umt, gilt die K\xfcndigung grunds\xe4tzlich als von Anfang an wirksam (\xa7 7 KSchG) \u2013 unabh\xe4ngig davon, ob sie eigentlich angreifbar gewesen w\xe4re.")
B.Rl=new A.cM("Auch als Verhandlungsweg","Die Klage dient nicht nur der Weiterbesch\xe4ftigung. Viele Verfahren enden mit einem Vergleich, in dem eine Abfindung vereinbart wird.")
B.a0C=s([B.Ra,B.Re,B.Rl],t.aX)
B.aJD=s(["\xa7 4 KSchG","\xa7 7 KSchG"],t.s)
B.RD=new A.hN(B.kj,"Die 3-Wochen-Frist f\xfcr die K\xfcndigungsschutzklage","Der wichtigste Termin \xfcberhaupt \u2013 nach Ablauf gilt die K\xfcndigung als wirksam.",B.a0C,B.aJD)
B.Rk=new A.cM("Wann melden?","Wer wei\xdf, dass sein Arbeitsverh\xe4ltnis endet, muss sich sp\xe4testens drei Monate vor dem Ende arbeitsuchend melden. Liegen zwischen Kenntnis und Ende weniger als drei Monate, muss die Meldung innerhalb von drei Tagen nach Kenntnis erfolgen (\xa7 38 SGB III).")
B.Rg=new A.cM("Wie melden?","Die Arbeitsuchendmeldung ist telefonisch, pers\xf6nlich oder online \xfcber die Website der Bundesagentur f\xfcr Arbeit m\xf6glich. Sie ist etwas anderes als die sp\xe4tere Arbeitslosmeldung.")
B.Rh=new A.cM("Warum das wichtig ist","Eine versp\xe4tete Meldung kann als Meldevers\xe4umnis eine Sperrzeit nach sich ziehen (\xa7 159 SGB III) und damit den ALG-Bezug verk\xfcrzen.")
B.aMh=s([B.Rk,B.Rg,B.Rh],t.aX)
B.aoJ=s(["\xa7 38 SGB III","\xa7 159 SGB III"],t.s)
B.RC=new A.hN(B.kk,"Arbeitsuchend melden \u2013 so fr\xfch wie m\xf6glich","Vers\xe4umnis kann eine Sperrzeit ausl\xf6sen. Die Meldung geht auch online.",B.aMh,B.aoJ)
B.R2=new A.cM("ALG 1: Versicherungsleistung","Arbeitslosengeld 1 ist eine Leistung der Arbeitslosenversicherung (SGB III). Voraussetzung ist eine Anwartschaftszeit von in der Regel zw\xf6lf Versicherungsmonaten. Die H\xf6he betr\xe4gt 60 % (mit Kind 67 %) des pauschalierten Nettoentgelts, die Dauer richtet sich nach Alter und Versicherungszeit.")
B.Rq=new A.cM("B\xfcrgergeld: Grundsicherung",'Das B\xfcrgergeld (SGB II, fr\xfcher \u201eALG 2"/Hartz IV) sichert den Lebensunterhalt unabh\xe4ngig von fr\xfcherer Besch\xe4ftigung. Es ist bed\xfcrftigkeitsabh\xe4ngig \u2013 Einkommen und Verm\xf6gen der Bedarfsgemeinschaft werden gepr\xfcft.')
B.Rv=new A.cM("Der \xdcbergang","Wer keinen oder keinen ausreichenden ALG-1-Anspruch hat oder dessen Anspruch ausl\xe4uft, kann erg\xe4nzend oder anschlie\xdfend B\xfcrgergeld beziehen.")
B.aNs=s([B.R2,B.Rq,B.Rv],t.aX)
B.aOx=s(["\xa7 149 SGB III","\xa7 147 SGB III","SGB II"],t.s)
B.Rz=new A.hN(B.kk,"ALG 1 oder B\xfcrgergeld (ALG 2)?","Versicherungsleistung gegen Grundsicherung \u2013 die wichtigsten Unterschiede.",B.aNs,B.aOx)
B.Rr=new A.cM("Ab dem ersten Tag","Die Arbeitslosmeldung erfolgt pers\xf6nlich oder online mit Wirkung ab dem ersten Tag der Besch\xe4ftigungslosigkeit. Der Antrag auf Arbeitslosengeld kann online gestellt werden.")
B.Rm=new A.cM("Wichtige Unterlagen","Der Arbeitgeber \xfcbermittelt der Agentur eine Arbeitsbescheinigung (\xa7 312 SGB III). Hilfreich sind au\xdferdem der K\xfcndigungs- bzw. Aufhebungsvertrag und Nachweise \xfcber Vorbesch\xe4ftigungen.")
B.Rc=new A.cM("Krankenversicherung nicht vergessen","Mit dem ALG-Bezug besteht in der Regel Versicherungsschutz. In einer L\xfccke zwischen Job und Leistung sollte der Krankenversicherungsschutz aktiv gekl\xe4rt werden.")
B.aLV=s([B.Rr,B.Rm,B.Rc],t.aX)
